module alu
(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);
    parameter ADD = 6'b100000;
    parameter ADDU = 6'b100001;
    parameter SUB = 6'b100010;
    parameter SUBU = 6'b100011;
    parameter AND = 6'b100100;
    parameter OR = 6'b100101;
    parameter XOR = 6'b100110;
    parameter NOR = 6'b100111;
    parameter SLT = 6'b101010;
    parameter SLTU = 6'b101011;
    parameter SLL = 6'b000000;
    parameter SRL = 6'b000010;
    parameter SRA = 6'b000011;
    parameter SLLV = 6'b000100;
    parameter SRLV = 6'b000110;
    parameter SRAV = 6'b000111;
    parameter LUI = 6'b001111;
    wire signed [31:0] sa = a, sb = b;
    reg [32:0] res;
    // assign r = res[31:0]; // DO NOT write this. It makes r a wire.
    always @(*) begin
        case (aluc)
            ADD  : res = sa + sb;  // add
            ADDU : res = a + b;  // addu
            SUB  : res = sa - sb;  // sub
            SUBU : res = a - b;  // subu
            AND  : res = a & b;  // and
            OR   : res = a | b;  // or
            XOR  : res = a ^ b;  // xor
            NOR  : res = ~(a | b);  // nor
            SLT  : res = sa < sb;  // slt
            SLTU : res = a < b;  // sltu
            SLL  : res = a << b[4:0];  // sll
            SRL  : res = a >> b[4:0];  // srl
            SRA  : res = sa >>> b[4:0];  // sra
            SLLV : res = a << b[4:0];  // sllv
            SRLV : res = a >> b[4:0];  // srlv
            SRAV : res = sa >>> b[4:0];  // srav
            LUI  : res = {a[15:0], 16'b0};  // lui
            default: res = 32'bz;
        endcase
        // if (aluc == ADD)  res = sa + sb;  // add
        // if (aluc == ADDU)  res = a + b;  // addu
        // if (aluc == SUB)  res = sa - sb;  // sub
        // if (aluc == SUBU)  res = a - b;  // subu
        // if (aluc == AND)  res = a & b;  // and
        // if (aluc == OR)   res = a | b;  // or
        // if (aluc == XOR)  res = a ^ b;  // xor
        // if (aluc == NOR)  res = ~(a | b);  // nor
        // if (aluc == SLT)  res = sa < sb;  // slt
        // if (aluc == SLTU)  res = a < b;  // sltu
        // if (aluc == SLL)  res = a << b[4:0];  // sll
        // if (aluc == SRL)  res = a >> b[4:0];  // srl
        // if (aluc == SRA)  res = sa >>> b[4:0];  // sra
        // if (aluc == SLLV)  res = a << b[4:0];  // sllv
        // if (aluc == SRLV)  res = a >> b[4:0];  // srlv
        // if (aluc == SRAV)  res = sa >>> b[4:0];  // srav
        // if (aluc == LUI)  res = {a[15:0], 16'b0};  // lui
    end
    assign r = res[31:0];
    assign zero = res == 0 ? 'b1 : 'b0;
    // assign zero = (res == 0); // NOT zero but (res == 0) is also illegal
    assign carry = 0;
    assign negative = res[31];
    assign overflow = 0;
    assign flag = 0;
    always @(*)
        case (aluc)
            SLT  : flag = sa < sb;
            SLTU : flag = a < b;
            default: flag = 1'b0;
        endcase
    // if (aluc == SLT && sa < sb)  flag = 1'b1;
    // if (aluc == SLTU && a < b)  flag = 1'b1;
endmodule
